urlset:
{{ range (where .Data.Pages "Kind" "not in" (slice "taxonomy" "term")) }}
  {{- if .Permalink -}}

  {{ .Permalink }}
  {{ if not .Lastmod.IsZero }}
  {{ safeHTML ( .Lastmod.Format "2006-01-02T15:04:05-07:00" ) }}
  {{ end }}

  {{- /* Logic for ChangeFreq */ -}}
  {{- $changefreq := "weekly" -}}
  {{- if .IsPage }}{{ $changefreq = "monthly" }}{{ end -}}
  {{- with .Sitemap.ChangeFreq }}{{ if ne . -1 }}{{ $changefreq = . }}{{ end }}{{ end -}}
  {{ $changefreq }}

  {{- /* Logic for Priority */ -}}
  {{- $priority := 0.5 -}}
  {{- if .IsHome }}{{ $priority = 1.0 }}{{ else if .IsPage }}{{ $priority = 0.8 }}{{ end -}}
  {{- with .Sitemap.Priority }}{{ if ne . -1.0 }}{{ $priority = . }}{{ end }}{{ end -}}
  {{ $priority }}

  {{ if .IsTranslated }}
  {{ range .AllTranslations }}

  {{ end }}
  {{ end }}

  {{- end -}}
{{ end }}
